INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd796dd09-7876-4def-a3f4-9a4c2858abe5',
  '00000000-0000-0000-0000-000000000001',
  $escape$Hono Dependency Injection — Manual Wiring via Context vs External Containers$escape$,
  $escape$Hono has no built-in DI container. Instead, it leans on its `Context` object as a lightweight service locator. You attach dependencies once at app startup using `app.use()` middleware, then retrieve them anywhere via `c.get()`. This pattern — sometimes called 'context injection' — is deliberately minimal: no decorators, no reflection, no IOC container overhead.

The tradeoff is testability. Because services live on `c`, unit-testing a handler means constructing a fake `Context` or using `app.request()` in integration style. For small apps this is fine. For larger codebases, teams wire Hono with external containers like `tsyringe` or `inversify`: the container resolves dependencies, handlers pull from `c.get()`, and the container itself is trivially swappable in tests.

The recommended pattern: define typed variables with `createFactory` (Hono v4+), bind services in a single middleware, and never import singletons directly inside handlers. This keeps handlers pure functions of context — easy to test, easy to swap.$escape$,
  $escape$import { Hono } from 'hono'
import { createFactory } from 'hono/factory'

type Env = { Variables: { db: Database; logger: Logger } }

const factory = createFactory<Env>()

const injectServices = factory.createMiddleware(async (c, next) => {
  c.set('db', new PostgresDatabase(process.env.DB_URL!))
  c.set('logger', new StructuredLogger())
  await next()
})

const app = new Hono<Env>()
app.use('*', injectServices)

app.get('/users/:id', factory.createHandlers(async (c) => {
  const db = c.get('db')
  const user = await db.findById(c.req.param('id'))
  return c.json(user)
}))$escape$,
  $escape$typescript$escape$,
