INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '92e879fb-eefe-4009-8c86-b6976c28d0f6',
  '00000000-0000-0000-0000-000000000001',
  $escape$Hono Project Structure — Vertical Slices Beat MVC at Scale$escape$,
  $escape$MVC feels natural at first in Hono — drop routes, controllers, and models into separate folders. But as your app grows, a feature change touches files across three directories. Vertical slices fix this by co-locating everything a feature needs.

In a vertical slice layout, each feature folder owns its Hono sub-app, validators, service logic, and types. You mount sub-apps onto the root app using `app.route()`. This means `/users` lives entirely in `src/features/users/` — its `router.ts` exports a `new Hono()` instance with all user-scoped routes, middleware, and handlers inline.

Layering still matters within each slice: keep pure business logic in a `service.ts`, HTTP concerns (parsing, response shaping) in the route handler, and Zod schemas in `schema.ts`. Hono's `zValidator` middleware slots cleanly into this — validate at the edge, pass typed data down to the service.

This structure scales horizontally: adding a `payments` feature means creating `src/features/payments/` and one `app.route('/payments', paymentsRouter)` call. No cross-feature coupling, no barrel-file sprawl.$escape$,
  $escape$// src/features/users/router.ts
import { Hono } from 'hono'
import { zValidator } from '@hono/zod-validator'
import { createUserSchema } from './schema'
import { createUser } from './service'

const users = new Hono()

users.post('/', zValidator('json', createUserSchema), async (c) => {
  const data = c.req.valid('json')
  const user = await createUser(data)
  return c.json(user, 201)
})

export default users

// src/index.ts
import { Hono } from 'hono'
import users from './features/users/router'

const app = new Hono()
app.route('/users', users)
export default app$escape$,
  $escape$typescript$escape$,
