INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ec720c4d-6388-41ac-b481-10640ba2ade4',
  '00000000-0000-0000-0000-000000000001',
  $escape$Hono JWT Auth — Middleware, Validation, and Session Patterns$escape$,
  $escape$Hono's `hono/jwt` middleware handles JWT validation with near-zero boilerplate. Mount `jwt({ secret })` on a route group and every request through it is automatically verified — no manual `verify()` calls needed. The decoded payload lands on `c.get('jwtPayload')`, giving you typed access to claims downstream.

For session-style auth, pair JWT with Hono's `setCookie`/`getCookie` helpers. Store a short-lived access token in an `HttpOnly` cookie and validate it with the same middleware. To scope auth to specific routes, use Hono's `app.use('/api/*', jwt({ secret }))` — unauthenticated requests get a 401 before your handler even runs.

For custom logic (role checks, token revocation via Redis), write a middleware that reads `c.get('jwtPayload')`, checks your store, then calls `next()` or returns early with `c.json({ error: 'Forbidden' }, 403)`. Chain it after `jwt()` on the same route group. Avoid re-verifying the token manually — trust the upstream middleware's result and focus your custom layer purely on authorization logic.$escape$,
  $escape$import { Hono } from 'hono'
import { jwt } from 'hono/jwt'

const app = new Hono()
const SECRET = process.env.JWT_SECRET!

// Role-check middleware (runs after jwt())
const requireAdmin = async (c: any, next: any) => {
  const payload = c.get('jwtPayload')
  if (payload?.role !== 'admin') return c.json({ error: 'Forbidden' }, 403)
  await next()
}

app.use('/admin/*', jwt({ secret: SECRET }))
app.use('/admin/*', requireAdmin)

app.get('/admin/dashboard', (c) => {
  const { sub, role } = c.get('jwtPayload')
  return c.json({ user: sub, role })
})

export default app$escape$,
  $escape$typescript$escape$,
